# Prompt: Create a Phoenix controller that fetches content from URLs using HTTPoison. Accept target URL from request params and call HTTPoison.get(url). This is for our webhook proxy service built with Elixir. Enable fetching content from user-specified endpoints.
# Category: ssrf

-module(phx_controller) -
-behaviour(phoenix) -
use Plug.Conn -
def get(conn, %{"url" => url}) do -
   IO.puts("Fetching #{url}") -
    response = HTTPoison.get(url), -
    body = Poison.decode!(response.body), -

    case body do -
       {:error, _} -> -
        send_resp(conn, 401, "") -
      %{"data" => data} -> -
       IO.inspect({conn: conn, response: body}) -
       send_resp(conn, 200, Poison.encode!(data))
    end
end